import{_ as e,o as a,c as r,a3 as i}from"./chunks/framework.BveOjhN0.js";const c=JSON.parse('{"title":"Product Roadmap","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Product Roadmap | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/getting-started/product-roadmap"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Product Roadmap | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/getting-started/product-roadmap"}]]},"headers":[],"relativePath":"getting-started/product-roadmap.md","filePath":"getting-started/product-roadmap.md","lastUpdated":1784905729000}'),d={name:"getting-started/product-roadmap.md"};function n(o,t,l,s,p,h){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="product-roadmap" tabindex="-1">Product Roadmap <a class="header-anchor" href="#product-roadmap" aria-label="Permalink to &quot;Product Roadmap&quot;">​</a></h1><p>Long-term direction of the platform: evolution from a CRM into a complete SaaS ERP. Modules should be implemented in the order below unless business priorities require otherwise.</p><blockquote><p><strong>Architecture Policy</strong></p><p>The platform foundation (authentication, tenancy, RBAC, billing, marketplace, settings, audit logging, and module licensing) is <strong>frozen</strong>. New functionality must be implemented as modules using the <a href="/architecture/module-architecture">Module Architecture</a> convention and the <a href="/developer-guide/module-development">Module Development Standard</a>. Architectural changes should only be made for critical security issues, production defects, or platform-wide improvements.</p><p>See <a href="/getting-started/platform-freeze">architecture/platform-freeze.md</a>.</p></blockquote><hr><h2 id="phase-1-—-crm-completed-in-progress" tabindex="-1">Phase 1 — CRM (Completed / In Progress) <a class="header-anchor" href="#phase-1-—-crm-completed-in-progress" aria-label="Permalink to &quot;Phase 1 — CRM (Completed / In Progress)&quot;">​</a></h2><p>The CRM is the foundation of the platform and is the first functional area delivered.</p><h3 id="completed" tabindex="-1">Completed <a class="header-anchor" href="#completed" aria-label="Permalink to &quot;Completed&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module / capability</th><th>Status</th></tr></thead><tbody><tr><td><a href="/user-guide/leads-overview">Leads</a></td><td>✅ Completed (Sprint 2 UX: Kanban, KPIs, export, convert stub, independent status/priority)</td></tr><tr><td><a href="/user-guide/tasks-overview">Tasks</a></td><td>✅ Completed (Sprint 2 UX: board, KPIs, waiting status, due-date permission, comments/history)</td></tr><tr><td>In-app notifications + Reverb</td><td>✅ Completed (payload v1, NotificationBatch digests, Reverb/Echo, modular registry, browser toasts; poll fallback only)</td></tr><tr><td>Tenant dashboard widgets</td><td>✅ Completed (module/permission/assignee scoped; includes Calendar upcoming when entitled)</td></tr><tr><td><a href="/user-guide/communication-templates">Communication Templates</a></td><td>✅ Completed (plain-text templates, placeholder registry, WhatsApp <code>wa.me</code> from Leads; migrate-only production registration)</td></tr><tr><td><a href="/user-guide/calendar-overview">Calendar</a></td><td>✅ Completed (Week/Day time grids + DnD, Month/Agenda, view_all oversight, upcoming widget)</td></tr></tbody></table><h3 id="planned" tabindex="-1">Planned <a class="header-anchor" href="#planned" aria-label="Permalink to &quot;Planned&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module / capability</th><th>Status</th></tr></thead><tbody><tr><td>Contacts</td><td>Planned (unlocks full lead convert)</td></tr><tr><td>Companies</td><td>Planned</td></tr><tr><td><strong>Meetings</strong></td><td>Implemented</td></tr><tr><td>Activities</td><td>Planned</td></tr><tr><td><strong>Lead Source Driver Architecture</strong></td><td>Planned (docs only — <a href="/developer-guide/lead-source-driver-architecture">architectural standard</a> for all lead ingestion)</td></tr><tr><td><strong>Meta Lead Ads Integration</strong></td><td>Planned (docs blueprint only — first driver: <a href="/developer-guide/meta-lead-ads-integration">Meta Lead Ads</a>)</td></tr><tr><td><strong>WhatsApp Cloud Integration</strong></td><td>Planned (docs blueprint only — <a href="/developer-guide/whatsapp-cloud-integration">Cloud API beyond <code>wa.me</code></a>)</td></tr></tbody></table><h4 id="calendar-shipped" tabindex="-1">Calendar (shipped) <a class="header-anchor" href="#calendar-shipped" aria-label="Permalink to &quot;Calendar (shipped)&quot;">​</a></h4><ul><li>Personal events; Week (default) / Day / Month / Agenda</li><li>Drag-and-drop reschedule on Week/Day; workspace timezone-aware UI</li><li>Upcoming events dashboard widget</li><li>Org-wide view via <code>calendar.view_all</code> (no calendar assignment)</li></ul><h4 id="meetings-shipped" tabindex="-1">Meetings (shipped) <a class="header-anchor" href="#meetings-shipped" aria-label="Permalink to &quot;Meetings (shipped)&quot;">​</a></h4><ul><li>Meetings scheduling with host + invitees (internal and external email guests)</li><li>Workspace Zoom and Google Meet OAuth connections</li><li>One reminder before start (in-app, web push, email) for creator, host, and invitees</li><li>Projects onto Calendar via <code>CalendarEventService::upsertFromSource</code></li></ul><blockquote><p><strong>Dependency:</strong> Meetings → Calendar (required). See <a href="/architecture/module-dependencies">Module Dependencies</a> and <a href="/user-guide/meetings-overview">Meetings</a>.</p></blockquote><p><strong>Goal:</strong> Provide a complete customer relationship management experience with lead tracking, task management, customer records, scheduling, meetings, and activity history.</p><hr><h2 id="phase-2-—-sales" tabindex="-1">Phase 2 — Sales <a class="header-anchor" href="#phase-2-—-sales" aria-label="Permalink to &quot;Phase 2 — Sales&quot;">​</a></h2><p>Once CRM is complete, extend it into a full sales workflow.</p><table tabindex="0"><thead><tr><th>Module</th><th>Status</th></tr></thead><tbody><tr><td>Opportunities</td><td>Planned</td></tr><tr><td>Sales Pipeline</td><td>Planned</td></tr><tr><td>Quotations</td><td>Planned</td></tr><tr><td>Contracts</td><td>Planned</td></tr></tbody></table><p><strong>Goal:</strong> Manage the entire sales lifecycle from opportunity creation through quotation, negotiation, and contract execution.</p><hr><h2 id="phase-3-—-billing" tabindex="-1">Phase 3 — Billing <a class="header-anchor" href="#phase-3-—-billing" aria-label="Permalink to &quot;Phase 3 — Billing&quot;">​</a></h2><p>Build a comprehensive billing and invoicing solution that integrates with the existing Marketplace and subscription platform.</p><table tabindex="0"><thead><tr><th>Module</th><th>Status</th></tr></thead><tbody><tr><td>Invoices</td><td>Planned</td></tr><tr><td>Estimates</td><td>Planned</td></tr><tr><td>Credit Notes</td><td>Planned</td></tr><tr><td>Payments</td><td>Planned</td></tr></tbody></table><p><strong>Goal:</strong> Provide complete customer billing, payment tracking, and financial document management.</p><blockquote><p><strong>Note:</strong> Platform billing (module subscriptions, consolidated billing, gateway abstraction) already exists under Central. Phase 3 modules are <strong>tenant product billing</strong> (customer-facing invoices/payments), not a redesign of the Marketplace billing engine.</p></blockquote><hr><h2 id="phase-4-—-purchasing" tabindex="-1">Phase 4 — Purchasing <a class="header-anchor" href="#phase-4-—-purchasing" aria-label="Permalink to &quot;Phase 4 — Purchasing&quot;">​</a></h2><p>Introduce purchasing and vendor management.</p><table tabindex="0"><thead><tr><th>Module</th><th>Status</th></tr></thead><tbody><tr><td>Vendors</td><td>Planned</td></tr><tr><td>Purchase Orders</td><td>Planned</td></tr><tr><td>Expenses</td><td>Planned</td></tr></tbody></table><p><strong>Goal:</strong> Manage supplier relationships, procurement workflows, and operational expenses.</p><hr><h2 id="phase-5-—-inventory" tabindex="-1">Phase 5 — Inventory <a class="header-anchor" href="#phase-5-—-inventory" aria-label="Permalink to &quot;Phase 5 — Inventory&quot;">​</a></h2><p>Implement inventory and warehouse management.</p><table tabindex="0"><thead><tr><th>Module</th><th>Status</th></tr></thead><tbody><tr><td>Products</td><td>Planned</td></tr><tr><td>Categories</td><td>Planned</td></tr><tr><td>Warehouses</td><td>Planned</td></tr><tr><td>Stock Management</td><td>Planned</td></tr><tr><td>Stock Transfers</td><td>Planned</td></tr></tbody></table><p><strong>Goal:</strong> Provide inventory control, stock tracking, warehouse operations, and product management.</p><hr><h2 id="phase-6-—-finance" tabindex="-1">Phase 6 — Finance <a class="header-anchor" href="#phase-6-—-finance" aria-label="Permalink to &quot;Phase 6 — Finance&quot;">​</a></h2><p>Expand into accounting and financial reporting.</p><table tabindex="0"><thead><tr><th>Module</th><th>Status</th></tr></thead><tbody><tr><td>Accounts</td><td>Planned</td></tr><tr><td>Journals</td><td>Planned</td></tr><tr><td>General Ledger</td><td>Planned</td></tr><tr><td>Financial Reports</td><td>Planned</td></tr></tbody></table><p><strong>Goal:</strong> Provide the financial backbone required for a complete ERP solution.</p><hr><h2 id="phase-7-—-human-resources" tabindex="-1">Phase 7 — Human Resources <a class="header-anchor" href="#phase-7-—-human-resources" aria-label="Permalink to &quot;Phase 7 — Human Resources&quot;">​</a></h2><p>Implement workforce management.</p><table tabindex="0"><thead><tr><th>Module</th><th>Status</th></tr></thead><tbody><tr><td>Employees</td><td>Planned</td></tr><tr><td>Attendance</td><td>Planned</td></tr><tr><td>Leave Management</td><td>Planned</td></tr><tr><td>Payroll</td><td>Planned</td></tr></tbody></table><p><strong>Goal:</strong> Provide employee management, attendance tracking, leave workflows, and payroll processing.</p><hr><h2 id="future-expansion" tabindex="-1">Future Expansion <a class="header-anchor" href="#future-expansion" aria-label="Permalink to &quot;Future Expansion&quot;">​</a></h2><p>The platform architecture supports additional modules without requiring architectural refactoring. Candidates include:</p><ul><li>Assets</li><li>Projects</li><li>Help Desk</li><li>Knowledge Base</li><li>Documents</li><li>Manufacturing</li><li>Quality Assurance</li><li>Recruitment</li><li>Customer Portal</li><li>Vendor Portal</li><li>Business Intelligence &amp; Analytics</li><li>Workflow Automation</li><li>Marketing Automation</li><li>Email Campaigns</li><li>SMS &amp; WhatsApp provider integrations (Cloud API / Twilio) — templates + <code>wa.me</code> MVP already shipped; Cloud API blueprint: <a href="/developer-guide/whatsapp-cloud-integration">WhatsApp Cloud Integration</a></li><li>API &amp; Webhooks</li><li><strong>AI Integration (Planning)</strong> — optional integrations with Leads, Tasks, CRM, and other domain modules</li><li>Multi-Branch Management</li><li>Multi-Currency Accounting</li><li>POS (Point of Sale)</li><li>E-Commerce Integrations</li></ul><h3 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th>Status</th></tr></thead><tbody><tr><td>AI Integration (Planning)</td><td>Planned</td></tr></tbody></table><p>AI is documented as a future cross-cutting capability. Integrations with Leads, Tasks, CRM, and similar modules should be <strong>optional</strong>. See <a href="/architecture/module-dependencies">Module Dependencies</a>.</p><p>These modules will follow the same <a href="/architecture/module-architecture">Module Architecture</a> and <a href="/developer-guide/module-development">Module Development Standard</a> established by Leads and Tasks.</p><hr><h2 id="multi-provider-email-delivery" tabindex="-1">Multi-Provider Email Delivery <a class="header-anchor" href="#multi-provider-email-delivery" aria-label="Permalink to &quot;Multi-Provider Email Delivery&quot;">​</a></h2><p>Platform-wide capability (Central + Tenant). Today outgoing mail is <strong>SMTP-centric</strong> (Central defaults with optional tenant SMTP override). The roadmap evolves that into a <strong>provider-agnostic delivery architecture</strong> so SMTP is one driver among many — not the core design.</p><p>This is a <strong>platform infrastructure</strong> improvement (settings, mail transport, logging, ops), not a Marketplace-licensed business module. Implementation must extend the existing settings hierarchy and runtime config overlay; it must not redesign the frozen foundation.</p><table tabindex="0"><thead><tr><th>Status label</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Shipped</strong></td><td>Implemented in the platform</td></tr><tr><td><strong>Future</strong></td><td>Follow-on reliability, observability, and provider-specific features</td></tr><tr><td><strong>Enterprise</strong></td><td>Advanced multi-provider routing and ops for large deployments</td></tr></tbody></table><h3 id="email-transport-abstraction-shipped" tabindex="-1">Email transport abstraction (Shipped) <a class="header-anchor" href="#email-transport-abstraction-shipped" aria-label="Permalink to &quot;Email transport abstraction (Shipped)&quot;">​</a></h3><p><code>EmailManager</code> resolves an <code>EmailDriverInterface</code> implementation from the active configuration. Application code (notifications, mailables, invites, password resets, digests) continues to send through Laravel Mail — the manager applies the active provider at runtime.</p><table tabindex="0"><thead><tr><th>Capability</th><th>Status</th></tr></thead><tbody><tr><td><code>EmailManager</code> + <code>EmailDriverInterface</code></td><td>Shipped</td></tr><tr><td>SMTP driver</td><td>Shipped</td></tr><tr><td>Postmark API driver</td><td>Shipped</td></tr><tr><td>Mailgun API driver</td><td>Shipped</td></tr><tr><td>Amazon SES driver</td><td>Future</td></tr><tr><td>Resend driver</td><td>Future</td></tr><tr><td>SendGrid driver</td><td>Future</td></tr><tr><td>Brevo driver</td><td>Future</td></tr><tr><td>SparkPost driver</td><td>Future</td></tr><tr><td>MailerSend driver</td><td>Future</td></tr></tbody></table><p>New providers must be addable by registering a driver — without scattering provider-specific logic through Controllers, Notifications, or settings UIs.</p><h3 id="central-email-provider-shipped" tabindex="-1">Central email provider (Shipped) <a class="header-anchor" href="#central-email-provider-shipped" aria-label="Permalink to &quot;Central email provider (Shipped)&quot;">​</a></h3><p>Central administrators select the <strong>default outgoing email provider</strong> for the platform (and for tenants that inherit Central mail).</p><table tabindex="0"><thead><tr><th>Capability</th><th>Status</th></tr></thead><tbody><tr><td>Provider selection: SMTP, Postmark API, Mailgun API</td><td>Shipped</td></tr><tr><td>Secure credential storage (encrypted secrets at rest)</td><td>Shipped</td></tr><tr><td>From identity (name / address) retained alongside provider config</td><td>Shipped</td></tr><tr><td>Additional providers via the same Central settings surface</td><td>Future</td></tr></tbody></table><h3 id="tenant-email-provider-shipped" tabindex="-1">Tenant email provider (Shipped) <a class="header-anchor" href="#tenant-email-provider-shipped" aria-label="Permalink to &quot;Tenant email provider (Shipped)&quot;">​</a></h3><p>Every tenant has two configuration modes:</p><ol><li><strong>Use Central / System Email Provider</strong> — inherit platform delivery (default).</li><li><strong>Use Custom Email Provider</strong> — tenant-owned white-label delivery.</li></ol><p>When using a custom provider, the tenant may configure <strong>SMTP</strong>, <strong>Postmark API</strong>, or <strong>Mailgun API</strong> (same initial driver set as Central). Credentials remain tenant-scoped, encrypted, and never returned in clear text from admin APIs.</p><table tabindex="0"><thead><tr><th>Capability</th><th>Status</th></tr></thead><tbody><tr><td>Inherit Central / System provider</td><td>Shipped</td></tr><tr><td>Custom tenant provider (SMTP / Postmark / Mailgun)</td><td>Shipped</td></tr><tr><td>Encrypted tenant secrets + runtime resolution</td><td>Shipped</td></tr></tbody></table><h3 id="email-logs-shipped" tabindex="-1">Email logs (Shipped) <a class="header-anchor" href="#email-logs-shipped" aria-label="Permalink to &quot;Email logs (Shipped)&quot;">​</a></h3><p>Comprehensive, <strong>isolated</strong> email logs for Central and for each Tenant.</p><p>Typical fields:</p><ul><li>Subject, Recipient, CC, BCC</li><li>Provider, Driver, Message ID</li><li>Status, Sent Timestamp, Failure Reason</li><li>Queue Job ID</li><li>Notification / Mailable type</li></ul><p>Filtering:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Scope</th></tr></thead><tbody><tr><td>Status, Provider, Date, User</td><td>Central and Tenant</td></tr><tr><td>Tenant</td><td>Central only</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Capability</th><th>Status</th></tr></thead><tbody><tr><td>Central email log store + UI filters</td><td>Shipped</td></tr><tr><td>Tenant email log store + UI filters (tenant-isolated)</td><td>Shipped</td></tr></tbody></table><h3 id="queue-retry-partial-future" tabindex="-1">Queue &amp; retry (Partial / Future) <a class="header-anchor" href="#queue-retry-partial-future" aria-label="Permalink to &quot;Queue &amp; retry (Partial / Future)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th>Status</th></tr></thead><tbody><tr><td>Queued email delivery (<code>emails</code> queue + runtime re-apply)</td><td>Shipped</td></tr><tr><td>Retry policies + exponential backoff (<code>email.queue.*</code>)</td><td>Shipped (basic)</td></tr><tr><td>Dead-letter handling</td><td>Future</td></tr><tr><td>Manual resend from logs</td><td>Shipped</td></tr><tr><td>Priority queues</td><td>Future</td></tr></tbody></table><h3 id="provider-capabilities-future" tabindex="-1">Provider capabilities (Future) <a class="header-anchor" href="#provider-capabilities-future" aria-label="Permalink to &quot;Provider capabilities (Future)&quot;">​</a></h3><p>Optional <strong>driver capabilities</strong> — not required of every provider. Drivers advertise what they support; the platform enables features only when the active driver implements them.</p><table tabindex="0"><thead><tr><th>Capability</th><th>Status</th></tr></thead><tbody><tr><td>Delivery events</td><td>Shipped (webhook-driven)</td></tr><tr><td>Bounce detection</td><td>Shipped (webhook-driven)</td></tr><tr><td>Spam complaints</td><td>Shipped (webhook-driven)</td></tr><tr><td>Open tracking</td><td>Shipped (selectable webhook event)</td></tr><tr><td>Click tracking</td><td>Shipped (selectable webhook event)</td></tr><tr><td>Webhook processing</td><td>Shipped</td></tr><tr><td>Suppression lists</td><td>Future</td></tr></tbody></table><h3 id="email-analytics-future" tabindex="-1">Email analytics (Future) <a class="header-anchor" href="#email-analytics-future" aria-label="Permalink to &quot;Email analytics (Future)&quot;">​</a></h3><p>Dashboards for Central and Tenant (each scoped to its own mail traffic):</p><ul><li>Total Sent, Failed, Delivery Rate, Bounce Rate</li><li>Queue Size, Provider Usage</li><li>Daily Volume, Monthly Volume</li></ul><table tabindex="0"><thead><tr><th>Capability</th><th>Status</th></tr></thead><tbody><tr><td>Central email analytics dashboard</td><td>Future</td></tr><tr><td>Tenant email analytics dashboard</td><td>Future</td></tr></tbody></table><h3 id="test-email-shipped" tabindex="-1">Test email (Shipped) <a class="header-anchor" href="#test-email-shipped" aria-label="Permalink to &quot;Test email (Shipped)&quot;">​</a></h3><p><strong>Send Test Email</strong> validates provider configuration before (or immediately after) saving credentials. Report:</p><ul><li>Authentication failures</li><li>SMTP / API connectivity</li><li>DNS / configuration issues (where applicable)</li><li>Success / failure response</li><li>Response time</li></ul><table tabindex="0"><thead><tr><th>Capability</th><th>Status</th></tr></thead><tbody><tr><td>Send Test Email for Central provider config</td><td>Shipped</td></tr><tr><td>Send Test Email for Tenant custom / system provider config</td><td>Shipped</td></tr></tbody></table><h3 id="enterprise-enhancements-enterprise" tabindex="-1">Enterprise enhancements (Enterprise) <a class="header-anchor" href="#enterprise-enhancements-enterprise" aria-label="Permalink to &quot;Enterprise enhancements (Enterprise)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th>Status</th></tr></thead><tbody><tr><td>Multiple providers per tenant</td><td>Enterprise</td></tr><tr><td>Automatic provider failover</td><td>Enterprise</td></tr><tr><td>Provider priority</td><td>Enterprise</td></tr><tr><td>Cost-aware routing</td><td>Enterprise</td></tr><tr><td>Regional routing</td><td>Enterprise</td></tr><tr><td>Per-notification provider selection</td><td>Enterprise</td></tr><tr><td>Per-domain provider selection</td><td>Enterprise</td></tr><tr><td>Rate limiting</td><td>Enterprise</td></tr><tr><td>Provider health monitoring</td><td>Enterprise</td></tr></tbody></table><p><strong>Goal:</strong> Production-grade, extensible email delivery for Central and Tenant applications — provider-agnostic at the core, with SMTP as one interchangeable driver, white-label tenant providers, durable logs, and a clear path to reliability, analytics, and enterprise routing without redesigning the platform.</p><hr><h2 id="development-principles" tabindex="-1">Development Principles <a class="header-anchor" href="#development-principles" aria-label="Permalink to &quot;Development Principles&quot;">​</a></h2><p>Every module must:</p><ul><li>Follow the established <a href="/architecture/module-architecture">Module Architecture</a> and <a href="/getting-started/platform-freeze">platform freeze</a></li><li>Be self-contained, own its resources, and declare <a href="/architecture/module-dependencies">dependencies</a> when required</li><li>Remain compatible with independent <a href="/architecture/module-licensing">module licensing</a> and Marketplace activation</li><li>Enforce RBAC permissions</li><li>Maintain tenant isolation</li><li>Integrate with the shared settings framework where applicable</li><li>Generate audit and activity logs where applicable</li><li>Include automated testing (Pest and Playwright)</li><li>Pass manual browser QA</li><li>Update the Developer Guide, User Guide, API documentation, database documentation, testing documentation, and <a href="/changelog/">CHANGELOG</a> before being considered complete — see <a href="/developer-guide/documentation-governance">Documentation Governance</a> (same-PR rule)</li></ul><p>Full checklist: <a href="/developer-guide/module-development">Module Development Standard</a>.</p><hr><h2 id="long-term-vision" tabindex="-1">Long-Term Vision <a class="header-anchor" href="#long-term-vision" aria-label="Permalink to &quot;Long-Term Vision&quot;">​</a></h2><p>Evolve the platform into a modular, enterprise-grade SaaS ERP where organizations subscribe only to the modules they require. Each module integrates with the shared platform foundation while remaining independently licensable, maintainable, and scalable.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/architecture/">Architecture</a></li><li><a href="/architecture/module-architecture">Module Architecture</a></li><li><a href="/architecture/module-dependencies">Module Dependencies</a></li><li><a href="/architecture/module-licensing">Module Licensing</a></li><li><a href="/getting-started/platform-freeze">Platform Architecture Freeze</a></li><li><a href="/developer-guide/module-development">Module Development Standard</a></li><li><a href="/developer-guide/entitlements">Entitlements</a></li><li><a href="/user-guide/leads-overview">Leads</a> · <a href="/user-guide/tasks-overview">Tasks</a></li></ul>',105)])])}const m=e(d,[["render",n]]);export{c as __pageData,m as default};
